INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 577, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'MFA significantly increases the complexity of social engineering attacks against human accounts. Implemented faithfully, it can be a deterrent to low-skill and/or financially motivated threat actors.', 'DETERRENT'),
                                              (3, 578, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'A strong implementation of MFA prevents a compromise of an account if only one of the factors has been breached by the attacker. In particular, physical tokens and biometrics are difficult to breach using remote phishing and/or social engineering - though not impossible.', 'PREVENTATIVE'),
                                              (4, 579, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Monitoring anomalies within MFA flows is a tested, high-fidelity method of detecting leaked credentials, with high volumes of failed MFA requests and/or explicit MFA denies being the principal avenue.', 'DETECTIVE'),
                                              (5, 580, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Requiring MFA to access external remote services adds a significant level of complexity to accessing remote services using compromised valid credentials. In addition, if paired with strong centralised authentication, it may largely mitigate the dangers of potentially insecure implementation of authentication within the services themselves. It is the single most effective control to prevent compromise of a legitimate external remote service using leaked credentials.', 'PREVENTATIVE'),
                                              (3, 581, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', U&'\000d\000aMFA significantly increases the complexity of social engineering attacks against human accounts. Implemented faithfully, it can be a deterrent to low-skill and/or financially motivated threat actors.', 'DETERRENT'),
                                              (1, 582, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID '4369b18e-df63-4636-be3a-3ea163137693', 'Although not primarily a control designed to prevent the exploitation of default credentials, MFA mandates may render some default accounts unworkable unless enrolled. If such accounts are enrolled, standard defences against valid accounts apply.', 'PREVENTATIVE'),
                                              (4, 583, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Corollary to the detection of misuse of valid accounts, anomalies within MFA usage are a good indication of compromised credentials and malicious remote service usage.', 'DETECTIVE'),
                                              (2, 584, UUID '591bdda4-2a62-4b24-9876-818cbfff5dac', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Similarly to external remote services, if MFA is required to access internal remote services, it can present a significant hurdle to attackers. However, configuring MFA in this way comes at a significant operational cost, and is not common in practice except for initial sign-in.', 'PREVENTATIVE'),
                                              (5, 585, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Device/software authentication is one of the strongest available protections against the insertion of rogue nodes in general. A well-designed device authentication scheme prevents the majority of such incidents with the exception of legitimate master node compromise.', 'PREVENTATIVE'),
                                              (2, 586, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Device/software authentication can prevent the misuse of remote services within the network from an untrusted/unknown source. However, this is a supplementary control. In practice, securing most remote services through device or software authentication is not operationally viable.', 'PREVENTATIVE'),
                                              (4, 587, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'A spike in unauthenticated activity, or a device that unsuccessfully attempts authentication against multiple endpoints, can be used as an indication of the presence of a rogue device.', 'DETECTIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 588, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'Strong device authentication prevents session hijacking or command injection, but doesn''t provide protection for passive observation of traffic or replay attacks unless session control is in place.', 'PREVENTATIVE'),
                                              (2, 589, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'A failure of counterparty authentication is endemic to active AitM attacks, but not sufficient to detect passive eavesdropping.', 'DETECTIVE'),
                                              (2, 590, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'Device/software authentication prevents unauthorised command messages from rogue devices or unsanctioned software. It does not provide any coverage for messages sent from legitimate control nodes.', 'PREVENTATIVE'),
                                              (2, 591, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Device/software authentication prevents unauthorised firmware updates from rogue devices or unsanctioned software. It does not provide any coverage for update commands sent from legitimate control nodes.', 'PREVENTATIVE'),
                                              (2, 592, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '042139c6-bfa4-4bac-af20-ecdc30cb9385', 'Device/software authentication prevents malicious activity from rogue devices or unsanctioned software. It does not provide any protection against activity from legitimate nodes.', 'PREVENTATIVE'),
                                              (2, 593, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID 'f9206252-e522-4d6b-89d2-98de01d91f45', 'Device/software authentication prevents malicious activity from rogue devices or unsanctioned software. It does not provide any protection against activity from legitimate nodes.', 'PREVENTATIVE'),
                                              (1, 594, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID 'c60f919a-e240-4574-8f76-fb194a960be2', 'Device/software authentication prevents malicious activity from rogue devices or unsanctioned software. It does not provide any protection against activity from legitimate nodes. In addition, attackers may still eavesdrop on network traffic (and infer operating mode from traffic patterns), and many devices do provide basic diagnostic information without any form of authentication required.', 'PREVENTATIVE'),
                                              (1, 595, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '3c13a4b7-b8c7-45a7-83f3-39c669fec70d', 'Device/software authentication prevents malicious restart/shutdown requests from rogue devices or unsanctioned software. It does not provide any protection against activity from legitimate nodes or physical access.', 'PREVENTATIVE'),
                                              (2, 596, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID 'b2dbcaa6-316a-4b34-92e4-47a78e9c7bb6', 'Device/software authentication prevents malicious activity from rogue devices or unsanctioned software. It does not provide any protection against activity from legitimate nodes', 'PREVENTATIVE'),
                                              (2, 597, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Device/software authentication prevents program tampering from rogue devices, but does not protect against compromised legitimate devices.', 'PREVENTATIVE'),
                                              (2, 598, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'Device/software authentication prevents program tampering from rogue devices, but does not protect against compromised legitimate devices.', 'PREVENTATIVE'),
                                              (2, 599, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID '7e158411-495e-4e93-92e4-65788a9474e9', 'Device authentication provides a level of protection against forged reporting messages from rogue devices, but does not protect against spoofed messages from legitimate nodes.', 'PREVENTATIVE'),
                                              (2, 600, UUID '6b5214cb-f6d9-44b6-90b2-cb08feb3aa5e', UUID 'f3b9dfe3-c532-48dc-943d-87d53f5d7588', U&'\000d\000aDevice authentication provides basic protection against the entry of unauthenticated devices into networks. However, it is insufficient as a standalone control to entirely prevent wireless compromise. Protocol-level authentication, application-layer controls, or MAC filtering is required to provide defence in depth.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 698, UUID '4d06d5b8-6bd7-4170-9ddb-a97e7c8fce64', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Account lockout policies may interrupt attacker activity when a high-risk sequence of account-related events is observed. This is a very common (and effective) control in IT, but significantly less useful in OT due to safety and availability constraints.', 'PREVENTATIVE'),
                                              (5, 699, UUID '4d06d5b8-6bd7-4170-9ddb-a97e7c8fce64', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'A robust set of account use policies can be used to establish a baseline of acceptable identity behaviour with regard to authentication and authorisation. Deviation from this baseline is a strong indication of suspicious activity, and detection based on account policy violations is difficult to circumvent - although prone to false positive detections.', 'DETECTIVE'),
                                              (4, 700, UUID '4d06d5b8-6bd7-4170-9ddb-a97e7c8fce64', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Account use policies are among the strongest available controls to prevent unauthorised access via VPN, remote gateways, or other similar services, despite operational friction.', 'PREVENTATIVE'),
                                              (4, 701, UUID '4d06d5b8-6bd7-4170-9ddb-a97e7c8fce64', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Deviations from standard behaviour are among the strongest available detective controls against misuse of remote services without exploitation in terms of identity compromise protection.', 'DETECTIVE'),
                                              (3, 702, UUID '4d06d5b8-6bd7-4170-9ddb-a97e7c8fce64', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Restricting resource usage to certain identities is an effective way to prevent identities from accessing resources that they are not required to access, therefore minimising the attack surface. In practice, the utility of this control is hampered by safety and availability requirements, as well as the operational complexity of establishing baseline policies.', 'PREVENTATIVE'),
                                              (4, 703, UUID '4d06d5b8-6bd7-4170-9ddb-a97e7c8fce64', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Deviations from standard behaviour are the strongest available detective controls against misuse of remote services without exploitation.', 'DETECTIVE'),
                                              (3, 704, UUID '5a08206b-140d-4bec-9445-68544a545429', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Stronger passwords are more resilient to compromises by brute force or rainbow tables. In addition, password age and history requirements in particular reduce risks posed by credential stuffing and password spraying, as they ensure timely rotation of passwords and prevent the use of weak passwords susceptible to password spraying.', 'PREVENTATIVE'),
                                              (5, 705, UUID '5a08206b-140d-4bec-9445-68544a545429', UUID '4369b18e-df63-4636-be3a-3ea163137693', 'Policies that require immediate password changes upon provisioning and enforce password strength are the strongest available defence against the use of default credentials such as ''admin''/''admin''', 'PREVENTATIVE'),
                                              (1, 706, UUID '5a08206b-140d-4bec-9445-68544a545429', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'An incidental benefit of password history policies is that it may prevent an attacker maintaining access through a previously used compromised password.', 'RECOVERY'),
                                              (3, 707, UUID '5a08206b-140d-4bec-9445-68544a545429', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'For external remote services that are exposed to the internet, password strength requirements are paramount to stop the ubiquitous automated probing attacks.', 'PREVENTATIVE'),
                                              (2, 708, UUID '5a08206b-140d-4bec-9445-68544a545429', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Strong passwords significantly impair brute force sign-ins into remote services where a valid account is not already available to the attackers. However, they do not meaningfully affect other types of attacks.', 'PREVENTATIVE'),
                                              (3, 709, UUID '5a08206b-140d-4bec-9445-68544a545429', UUID '245d3bec-ea7e-4010-8354-60d6b07fe1f7', 'Internet accessible devices can be vulnerable to brute forcing, especially in combination with default credentials and a lack of account lockout policies. Password strengthening policies meaningfully increase the complexity of such brute force attacks where a password is targeted.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 835, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', U&'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. \000d\000a\000d\000aNote that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 836, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID 'f9206252-e522-4d6b-89d2-98de01d91f45', U&'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. \000d\000a\000d\000aNote that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (4, 837, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '4369b18e-df63-4636-be3a-3ea163137693', 'Preventing the misuse of default/hardcoded credentials is one of the primary purposes of authentication gateways/proxies. By requiring authentication against a sentinel network node with strong segmentation, the risks posed by default credentials are minimised at the segment boundary. Residual risk remains from in-segment traffic and access vectors outside of the access control node.', 'PREVENTATIVE'),
                                              (3, 838, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'An authentication proxy/gateway may be configured to log authentication attempts and thus attempts to use default credentials while signing in - if default credential sign-in attempts are performed across segment boundaries.', 'DETECTIVE'),
                                              (2, 839, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID 'c60f919a-e240-4574-8f76-fb194a960be2', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 840, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '3c13a4b7-b8c7-45a7-83f3-39c669fec70d', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 841, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '997e3c17-ff06-4677-9c7d-f8149fe2cc8f', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (4, 842, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '547689fb-51f3-4078-852d-4dea4bc6be0d', U&'Preventing the misuse of default/hardcoded credentials is one of the primary purposes of authentication gateways/proxies. By requiring authentication against a sentinel network node with strong segmentation, the risks posed by default credentials are minimised at the segment boundary. \000d\000a\000d\000aResidual risk remains from in-segment traffic and access vectors outside of the access control path. ', 'PREVENTATIVE'),
                                              (2, 843, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID 'b2dbcaa6-316a-4b34-92e4-47a78e9c7bb6', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 844, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '10c96bfc-c884-413d-bb61-cbdc1abfc556', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 845, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '14fb1d12-0a85-403f-af59-3dc4b9001dca', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 846, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 847, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (2, 848, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 849, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID '01509832-f76c-4fdf-8aee-688667a163b3', 'Depending on their settings and hardening policies in place, authentication proxies can help enforce strong authentication and authorisation for critical field device operations, thus significantly reducing the risks of unauthorised activity from malicious third parties. Note that the mere existence of a proxy/gateway only reduces individual devices&#39; attack surface by requiring authentication before interacting with field devices. The vast majority of benefits is only realised using policy-level controls.', 'PREVENTATIVE'),
                                              (1, 850, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Authentication gateways can be used to enable and enforce conditional access policies, but possess comparatively little preventative value as a standalone control. The primary benefit in this regard is a potential reduction of attack surface for extraction of valid accounts.', 'PREVENTATIVE'),
                                              (3, 851, UUID 'e546cdc9-08f8-4791-813d-f27df57acfd6', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'If configured properly, an authentication gateway may log all authentication towards a given network or functional segment. This can significantly aid in auditing of access. However, this coverage is localised, and does not include lateral authentication that does not pass the proxy/gateway node.', 'DETECTIVE'),
                                              (5, 852, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Remote access can be disabled and only enabled for technicians during given time windows. If enforced correctly, this is one of the most effective mitigations against external remote service misuse. ', 'PREVENTATIVE'),
                                              (2, 853, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'By minimising standing privileges, this technique can readily reduce the opportunity for misuse of compromised valid accounts. However, practical implementation is typically hampered by operational requirements and is not practical outside of accounts that aren''t used regularly.', 'PREVENTATIVE'),
                                              (3, 854, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '9cbe4c82-270a-431f-8fa6-09db2a3170c5', 'If access is only granted for a given resource at a given time, the window for lateral movement is limited to access window. This is especially effective for mitigating lateral tool transfer from engineering workstations and contractor workstations to PLCs.', 'PREVENTATIVE'),
                                              (3, 855, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '51ec697b-6556-4117-a055-652f67dad1b2', 'Setpoint changes (e.g., changing a pressure limit) can be configured to require a JIT elevation. This prevents parameter drift by unauthorized users, although may not be available for all parameters.', 'PREVENTATIVE'),
                                              (2, 856, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '7e0f1de4-eeb4-427a-9879-668e55527eb0', 'JIT can be set to enforce that PLC logic changes can only occur during an approved window, typically requiring a second person (manager/operator) to approve the JIT request. This may not be viable for all processes and must not interfere with critical functions. For controller tasking, this control is less effective due to the comparatively rapid frequency of controller task changes and the overhead associated with JIT.', 'PREVENTATIVE'),
                                              (3, 857, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '7edb70b6-837a-499d-927d-bebb113797db', 'JIT enforces that PLC program changes can only occur during an approved window, typically requiring a second person (manager/operator) to approve the JIT request. However, enforcing JIT policies can be tricky, especially on older PLCs.', 'PREVENTATIVE'),
                                              (3, 858, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'JIT enforces that PLC program changes can only occur during an approved window, typically requiring a second person (manager/operator) to approve the JIT request. However, enforcing JIT policies can be tricky, especially on older PLCs.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 859, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '01509832-f76c-4fdf-8aee-688667a163b3', 'JIT enforces that firmware changes can only occur during an approved window from an approved source, typically requiring a second person (manager/operator) to approve the JIT request. However, enforcing JIT policies can be tricky, especially on older PLCs.', 'PREVENTATIVE'),
                                              (3, 860, UUID 'f32d345e-f53d-4f6c-ac2a-9874e7fdc01f', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'JIT enforces that firmware change mode can only be activated during an approved window, typically requiring a second person (manager/operator) to approve the JIT request. However, enforcing JIT policies can be tricky, especially on older PLCs.', 'PREVENTATIVE'),
                                              (2, 870, UUID '192ce200-ce17-4368-bb93-a9382e7323d2', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Implementing centralised authentication does not (on its own) meaningfully prevent attackers from misusing valid accounts, but may help reduce the attack surface by reducing the number of opportunities to extract credentials from systems.', 'PREVENTATIVE'),
                                              (4, 871, UUID '192ce200-ce17-4368-bb93-a9382e7323d2', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Centralised authentication solutions provide a nexus for all authentication activity, allowing security teams to audit authentication and monitor for anomalies and/or indicators of compromise.', 'DETECTIVE'),
                                              (4, 872, UUID '192ce200-ce17-4368-bb93-a9382e7323d2', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Centralised authentication platforms allow administrators to quickly block, revoke or remedy compromised identities within the system, significantly reducing time to respond.', 'CONTAINMENT'),
                                              (4, 873, UUID '192ce200-ce17-4368-bb93-a9382e7323d2', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Centralised authentication platforms allow for central execution of remediation actions (e.g., credential reset, identity re-creation).', 'RECOVERY'),
                                              (3, 874, UUID '192ce200-ce17-4368-bb93-a9382e7323d2', UUID '4369b18e-df63-4636-be3a-3ea163137693', U&'Centralised authentication precludes the use of default credentials to authenticate against systems, significantly reducing the attack surface (in conjunction with disabling default credentials).\000d\000a\000d\000aUnfortunately, not all resources may support IdP integration. This can be partially mitigated by adding an authentication proxy in front of critical resources. In addition, in some cases, undocumented and/or hardcoded default credentials may remain, further undermining the efficacy.', 'PREVENTATIVE'),
                                              (2, 875, UUID '192ce200-ce17-4368-bb93-a9382e7323d2', UUID '4369b18e-df63-4636-be3a-3ea163137693', 'Depending on exact configuration of all involved systems, the centralised authentication solution may log attempts to use default credentials. ', 'DETECTIVE'),
                                              (2, 876, UUID '192ce200-ce17-4368-bb93-a9382e7323d2', UUID 'a24d533c-08e3-46f2-a92d-4dd5696b1927', U&'Central authentication can help offload authentication management from services themselves and potentially ensure a robust authentication flow if proper policies are applied and followed. The magnitude of this effect is entirely dependent on the\000d\000apolicies. The mere existence of centralised authentication only provides protection against exploitation of individual services'' authentication mechanisms by removing them from the flow, and only if configured.  ', 'PREVENTATIVE'),
                                              (1, 877, UUID '92752457-0323-4431-af10-455c39d0e510', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Usage of PKI for authentication reduces the attack surface for compromising valid accounts whose credentials may be stored in credential stores, provided that certificates are used in adherence with best practices. ', 'PREVENTATIVE'),
                                              (3, 878, UUID '92752457-0323-4431-af10-455c39d0e510', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', U&'Known compromised certificates can be centrally revoked, immediately preventing them from being used for further exploitation, provided that the certificate revocation list or OCSP is correctly implemented and available at the time of authentication.\000d\000a\000d\000aIn addition, only systems that support PKI are covered.', 'CONTAINMENT');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 879, UUID '92752457-0323-4431-af10-455c39d0e510', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Authentication attempts with expired or revoked certificates can be detected. However, such case are typically marginal in operations, with the vast majority of such alerts being the result of a failure to renew certificates before expiration.', 'DETECTIVE'),
                                              (2, 880, UUID '92752457-0323-4431-af10-455c39d0e510', UUID '875e36e3-379b-4e53-aecc-b32c6420ac89', 'PKI is effective at preventing attackers from impersonating devices or systems. In addition, it enables further controls such as code signing that make masquerading nearly unworkable - although by default, the mere deployment of a PKI does not fully prevent such activities.', 'DETERRENT'),
                                              (4, 881, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Hardware tokens are widely seen to be among the most robust authentication methods, typically requiring both physical proximity (or dedicated embedded hardware) and the possession of the correct hardware key. In addition, they render credential compromise (phishing, extraction from files...) functionally unworkable as a method of obtaining valid account access.', 'PREVENTATIVE'),
                                              (3, 882, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Hardware authentication tokens provide a strong evidence of someone''s identity and physical presence if misused for malicious purposes. This makes them effective at deterring some malicious insiders from executing hostile activities.', 'DETERRENT'),
                                              (4, 883, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Compromised account credentials that require the possession of a physical security key cannot be used for lateral movement unless the attacker also possesses the key.', 'CONTAINMENT'),
                                              (4, 884, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'External remote services accessed by vendors or remote personnel can be often configured to only accept connections from trusted devices (using TPM authentication). This vastly reduces the risk posed by such services, as they can only be used by known managed devices.', 'PREVENTATIVE'),
                                              (2, 885, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'While standard MFA (like push notifications) on web services can be bypassed by session hijacking, hardware tokens may use cryptographic origin binding to ensure the token only works on the legitimate site, neutralizing proxy-based phishing. This is a well known application of hardware tokens in general IT. In OT environments, this benefit is more incidental, as online MFA is nearly never a practical alternative.', 'PREVENTATIVE'),
                                              (4, 886, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID '0c73af56-2e63-4fd2-b9af-fa2ef47fd560', 'If hardware devices such as smart cards are used to access areas within the industrial installations, they provide a strong evidence of a person''s presence and thus a deterrent to performing damaging actions.', 'DETERRENT'),
                                              (4, 887, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Many devices have default credentials from the factory. However, if a hardware token is required to use them, they are rendered ineffective for an attacker to use', 'PREVENTATIVE'),
                                              (2, 888, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'The events produced by hardware authentication tokens themselves do not reliably capture malicious activity in their own right, but they may be invaluable in tracing the chain of malicious activity across the environment.', 'DETECTIVE'),
                                              (3, 889, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID '62b43417-d30a-4b6e-82d5-3dbfcc34d586', 'Physical tokens can be used to verify that higher order changes that may result in a loss of control have been performed by a physically present, authorised operator. This is instrumental in minimising the impacts of remote exploitation, but may not be supported by all systems.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 890, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID 'b46c9062-aa61-45c4-a309-a2bd37db750b', 'Physical tokens can be used to verify that higher order changes that may result in a loss of safety have been performed by a physically present, authorised operator. This is instrumental in minimising the impacts of remote exploitation, but may not be supported by all systems.', 'PREVENTATIVE'),
                                              (3, 891, UUID 'a6979daa-f9ce-4d8d-8594-c4528e996711', UUID 'b4c2adb3-9e17-4e75-9575-af502cc6630e', 'Physical tokens can be used to verify that higher order changes that may result in a loss of protection have been performed by a physically present, authorised operator. This is instrumental in minimising the impacts of remote exploitation, but may not be supported by all systems.', 'PREVENTATIVE'),
                                              (4, 892, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 893, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '068d9598-1033-451f-9597-88a8c59bd522', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 894, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '9fc41a50-2eb0-4999-ac4f-c2fcf8da2c3d', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 895, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'f9206252-e522-4d6b-89d2-98de01d91f45', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 896, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'e30b2106-cea9-43f4-8696-9a4b6be50635', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 897, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '3c13a4b7-b8c7-45a7-83f3-39c669fec70d', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 898, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '997e3c17-ff06-4677-9c7d-f8149fe2cc8f', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 899, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 900, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '6f4f3300-def7-40ed-9c94-1feccc807831', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 901, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '62b43417-d30a-4b6e-82d5-3dbfcc34d586', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 902, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '328fb14f-e537-43b3-90d5-180aed981208', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (4, 903, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'b4c2adb3-9e17-4e75-9575-af502cc6630e', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 904, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'b46c9062-aa61-45c4-a309-a2bd37db750b', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 905, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'ca099b14-f16e-4662-90f2-e17726222363', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 906, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'b2dbcaa6-316a-4b34-92e4-47a78e9c7bb6', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 907, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '7e0f1de4-eeb4-427a-9879-668e55527eb0', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 908, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '51ec697b-6556-4117-a055-652f67dad1b2', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 909, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '7edb70b6-837a-499d-927d-bebb113797db', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 910, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '10c96bfc-c884-413d-bb61-cbdc1abfc556', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (3, 911, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'ed8ea5cc-fda1-499e-a0d6-5b2f564e3954', U&'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.\000d\000a\000d\000aFor process state monitoring specifically, the impact is somewhat diminished by the fact that process state information is typically widely available across roles.', 'PREVENTATIVE'),
                                              (4, 912, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 913, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 914, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '10c96bfc-c884-413d-bb61-cbdc1abfc556', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'DETERRENT'),
                                              (4, 915, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (4, 916, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 917, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '69567f8a-8678-4c68-94f6-135ad7df352a', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 918, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'fddfa472-9838-4855-a4da-39fe354f5241', 'Access control is invaluable in limiting the impacts of supply chain compromise by restricting trusted technologies and vendors only to a limited subset of functions aligned with their role within the environment.', 'CONTAINMENT'),
                                              (4, 919, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID '01509832-f76c-4fdf-8aee-688667a163b3', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 920, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (2, 921, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'cd3ac01b-ede9-4745-b684-9d3885622d13', 'Proper access control reduces the blast radius of user execution by restricting the set of resources the compromised user has access to.', 'CONTAINMENT'),
                                              (2, 922, UUID '8adc6c2a-6e25-4134-9f64-c2c9bf7f3a9a', UUID 'a1fb03c7-0f3c-4d88-bea0-49e399e52c69', 'Access control techniques can limit the blast radius of transient assets, but do not meaningfully prevent their exploitation.', 'CONTAINMENT'),
                                              (4, 923, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.', 'PREVENTATIVE'),
                                              (4, 924, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse. ', 'PREVENTATIVE'),
                                              (3, 925, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'ABAC can help prevent the misuse of valid accounts by providing conditional access policies. Under such policies, even a valid sign-in may not be admitted into the environment if it doesn''t meet criteria such as time of day, device enrolment into management technologies, location, etc.', 'PREVENTATIVE'),
                                              (4, 926, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID 'f9206252-e522-4d6b-89d2-98de01d91f45', U&'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse.\000d\000a\000d\000aABAC is especially effective at enforcing operating mode change authorisation, as it can ensure that the operating mode change satisfies operational and process requirements.', 'PREVENTATIVE'),
                                              (3, 927, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID 'c60f919a-e240-4574-8f76-fb194a960be2', 'Operating mode information should only be available to authorised users.', 'PREVENTATIVE'),
                                              (3, 928, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '3c13a4b7-b8c7-45a7-83f3-39c669fec70d', 'Ensure that device restarts and shutdowns must follow an authorisation unless an emergency shutdown is required.', 'PREVENTATIVE'),
                                              (2, 929, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '997e3c17-ff06-4677-9c7d-f8149fe2cc8f', 'ABAC can help secure APIs as well, though the capabilities for ABAC within APIs tend to be limited. An authorisation gateway is frequently needed.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 930, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID 'b2dbcaa6-316a-4b34-92e4-47a78e9c7bb6', 'ABAC can compensate for a lack of RBAC during alarm settings modification, but is typically a less powerful control.', 'PREVENTATIVE'),
                                              (2, 931, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '10c96bfc-c884-413d-bb61-cbdc1abfc556', 'ABAC can compensate for a lack of RBAC during program modification, but is typically a less powerful control.', 'PREVENTATIVE'),
                                              (4, 932, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '7e0f1de4-eeb4-427a-9879-668e55527eb0', 'ABAC is especially effective at ensuring that controller tasks are within specified parameters.', 'PREVENTATIVE'),
                                              (3, 933, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '51ec697b-6556-4117-a055-652f67dad1b2', 'Correctly configured access control restricts sensitive operations to authorised personnel and services only, thus forming one of the primary means of prevention of their misuse. In case of parameter modification, ABAC can provide additional coverage by validating the circumstances of parameter modification, although this is a situational benefit.', 'PREVENTATIVE'),
                                              (2, 934, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '7edb70b6-837a-499d-927d-bebb113797db', 'ABAC can compensate for a lack of RBAC during program modification, but is typically a less powerful control.', 'PREVENTATIVE'),
                                              (3, 935, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '14fb1d12-0a85-403f-af59-3dc4b9001dca', 'Point and tag information can be restricted to a subset of identities based on identity attributes. This provides baseline defence against unauthorised identification, though the robustness of this control heavily depends on the exact implementation.', 'PREVENTATIVE'),
                                              (2, 936, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'ABAC can compensate for a lack of RBAC during program download, but is typically a less powerful control.', 'PREVENTATIVE'),
                                              (2, 937, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'ABAC can compensate for a lack of RBAC during program upload, but is typically a less powerful control.', 'PREVENTATIVE'),
                                              (2, 938, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'ABAC can compensate for a lack of RBAC during remote service invocation, but is typically a less powerful control.', 'PREVENTATIVE'),
                                              (3, 939, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'ABAC can help reduce the blast radius of a compromised valid account by restricting its permissions based on the sign-in attributes. ', 'CONTAINMENT'),
                                              (3, 940, UUID 'd161baf8-ab35-4992-a174-ca290ef296b7', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Violations of access policies can be monitored and potentially highlight users with anomalous attributes that may be compromised.', 'DETECTIVE'),
                                              (4, 949, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID '0c73af56-2e63-4fd2-b9af-fa2ef47fd560', 'Physical access control is instrumental in preventing physical sabotage using mechanical means, such as theft or physical damage.', 'PREVENTATIVE'),
                                              (3, 950, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID '0c73af56-2e63-4fd2-b9af-fa2ef47fd560', 'A strong physical access control system including biometric and/or RFID keys may pose a barrier against even attempting to damage property behind locked enclosures - requiring the threat actor to bypass the access control before enacting any destruction.', 'DETERRENT'),
                                              (3, 951, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID 'c153fbb5-5cd4-4753-aedf-048b4ae49adf', 'Physical access controls prevent a subset of attacks that relies on physically tampering with the I/O devices - such as shorting pins or physical connections of rogue devices.', 'PREVENTATIVE'),
                                              (3, 952, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID 'c0931c4b-efbf-4932-a1d1-63a5d23f932a', 'Threat actors may attempt to physically compromise wired networks, for example by connecting rogue devices into switches or network hubs. Strong physical access control will prevent such activity.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 953, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'Threat actors may attempt to physically compromise wired networks, for example by connecting rogue devices into switches or network hubs. Strong physical access control will prevent such activity. This is a relatively uncommon way of achieving adversary-in-the-middle attacks, but not unheard of.', 'DETERRENT'),
                                              (3, 954, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID 'b46c9062-aa61-45c4-a309-a2bd37db750b', 'Physical interlocks are an industry standard way to prevent access to devices and installations while they are in an unsafe condition. Similarly, procedures such as Lockout-tagout (LOTO) are instrumental in preventing the emergence of unsafe states, such as powering up a machine while maintenance is still being performed on it.', 'PREVENTATIVE'),
                                              (3, 955, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID 'b46c9062-aa61-45c4-a309-a2bd37db750b', 'A strong accountability and physical access control system makes negligent or malicious bypasses of physical safety features very costly to threat actors.', 'DETERRENT'),
                                              (4, 956, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID 'dc9f35b2-2d95-4f3a-8a53-bfc85260e23a', 'HMIs that are located within physically sequestered areas and have tight physical access controls will not be accessible to malicious actors unless they are authorised to be present and unless remote access is possible.', 'PREVENTATIVE'),
                                              (3, 957, UUID 'b3e7c959-91b8-44c2-9190-1f138274fdb5', UUID 'ca29a3a1-027c-4ebd-9496-a4a910a2feb8', 'Physical access control prevents unauthorised attackers from physically accessing control equipment and thus significantly reduces the risk of unauthorised threat actors influencing control flows via physical interaction.', 'PREVENTATIVE'),
                                              (5, 958, UUID 'e273bee2-4b74-4742-8b43-a8efd4fc51c1', UUID 'b46c9062-aa61-45c4-a309-a2bd37db750b', 'Break glass protocols in ICS are the primary defence against unsafe operational conditions. They are enacted in emergency situations, typically with a decisive, drastic impact.', 'CONTAINMENT'),
                                              (5, 959, UUID 'e273bee2-4b74-4742-8b43-a8efd4fc51c1', UUID '62b43417-d30a-4b6e-82d5-3dbfcc34d586', 'Break glass protocols can deny control of an environment to an attacker by forcing the system to a known safe state. However, due to the downstream effects, such actions are inevitably highly costly.', 'CONTAINMENT'),
                                              (3, 960, UUID 'e273bee2-4b74-4742-8b43-a8efd4fc51c1', UUID '62b43417-d30a-4b6e-82d5-3dbfcc34d586', 'Break-glass accounts are typically highly privileged and can often override an attacker that denies control to authorised operators. Note that this benefit is situational and may not apply to situations where the loss of control was caused by a functional loss of equipment or infrastructure.', 'PREVENTATIVE'),
                                              (2, 961, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID 'feafa416-a00e-4492-8347-e1ae3fa47922', 'Dual control requires two accounts to confirm an action; the compromise of a single one may not be sufficient for the threat actor to perform their activities. However, dual control is only practical in a limited set of scenarios and thus is unlikely to have a wide coverage.', 'PREVENTATIVE'),
                                              (2, 962, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID '62b43417-d30a-4b6e-82d5-3dbfcc34d586', 'Dual control requires two accounts to confirm an action; the compromise of a single one may not be sufficient for the threat actor to perform their activities. However, it is unlikely to cover the majority of loss of control scenarios.', 'PREVENTATIVE'),
                                              (2, 963, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID '6f4f3300-def7-40ed-9c94-1feccc807831', 'Dual control requires two accounts to confirm an action; the compromise of a single one may not be sufficient for the threat actor to perform their activities. However, it is unlikely to cover the majority of loss of control scenarios.', 'PREVENTATIVE'),
                                              (1, 964, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID '328fb14f-e537-43b3-90d5-180aed981208', 'Dual control requires two accounts to confirm an action; the compromise of a single one may not be sufficient for the threat actor to perform their activities. Only a small set of productivity-impacting activities is likely to be covered.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (2, 965, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID 'b4c2adb3-9e17-4e75-9575-af502cc6630e', 'Dual control requires two accounts to confirm an action; the compromise of a single one may not be sufficient for the threat actor to perform their activities. However, it is unlikely to cover the majority of loss of protection scenarios.', 'PREVENTATIVE'),
                                              (3, 966, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID 'b46c9062-aa61-45c4-a309-a2bd37db750b', 'Dual control requires two accounts to confirm an action; the compromise of a single one may not be sufficient for the threat actor to perform their activities. This is absolutely critical in major safety systems and a recommended practice in dangerous industries. It is, however, unlikely to prevent common operational safety violations due to the typically limited scope of such controls.', 'PREVENTATIVE'),
                                              (4, 967, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID 'b46c9062-aa61-45c4-a309-a2bd37db750b', 'The presence of a second operator is a powerful deterrent to a malicious insider executing sabotage. The coverage is however reduced by the operational constraints and the usually low proliferation of dual-custody controls.', 'DETERRENT'),
                                              (3, 968, UUID '80b6dee5-76ae-438f-b8b0-657dab20c0f4', UUID '62b43417-d30a-4b6e-82d5-3dbfcc34d586', 'The presence of a second operator is a powerful deterrent to a malicious insider executing sabotage. The coverage is however reduced by the operational constraints and the usually low proliferation of dual-custody controls.', 'DETERRENT'),
                                              (4, 989, UUID '1b175662-1a20-4c64-a484-7e95f9bc1f14', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'Safely authenticating communication counterparties under all circumstances is an effective way to prevent adversaries from inserting themselves into confidential communication.', 'PREVENTATIVE'),
                                              (4, 990, UUID '1b175662-1a20-4c64-a484-7e95f9bc1f14', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'Failed counterparty authentication challenges are a highly effective way of detecting AitM attacks.', 'DETECTIVE'),
                                              (4, 991, UUID '1b175662-1a20-4c64-a484-7e95f9bc1f14', UUID '7e158411-495e-4e93-92e4-65788a9474e9', 'Authenticating the source of a reporting message is one of the most reliable methods of preventing message spoofing from illegitimate sources.', 'PREVENTATIVE'),
                                              (4, 992, UUID '1b175662-1a20-4c64-a484-7e95f9bc1f14', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'Authenticating the source of a command message is one of the most reliable methods of preventing message spoofing from illegitimate sources.', 'PREVENTATIVE'),
                                              (2, 993, UUID '1b175662-1a20-4c64-a484-7e95f9bc1f14', UUID '3b69a362-0354-4843-8444-21340e9d14ce', 'Network device authentication may prevent communication towards untrusted proxies, preventing a category of low sophistication uses of the proxy method.', 'PREVENTATIVE'),
                                              (3, 994, UUID '1b175662-1a20-4c64-a484-7e95f9bc1f14', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'Requiring authentication for all communication counterparties may deter attackers from attempting AitM attacks by imposing a high technical barrier to entry.', 'DETERRENT'),
                                              (4, 1016, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'dcb3fa1e-23e5-45ef-b6a3-b1961203f07d', 'Traffic filtering using firewalls is an effective way to stop data egress from within network segments, as well as traffic to malicious destinations or traffic with suspicious patterns. A properly configured firewall can therefore nearly eliminate opportunities for automated collection.', 'PREVENTATIVE'),
                                              (4, 1017, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'dcb3fa1e-23e5-45ef-b6a3-b1961203f07d', 'Firewall logs are the primary means of detecting automated collection patterns.', 'DETECTIVE'),
                                              (4, 1018, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'd4732c86-bcec-4593-bc86-96edc8c8acf8', 'Firewalls are the primary method of filtering network traffic. This is invaluable in stopping and/or detecting malicious communication over standard application layer protocols.', 'PREVENTATIVE'),
                                              (4, 1019, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'd4732c86-bcec-4593-bc86-96edc8c8acf8', 'Firewalls are the primary method of filtering network traffic. This is invaluable in stopping and/or detecting malicious communication over standard application layer protocols.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 1020, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Firewalls can be configured to filter packets associated with firmware update mode unless they arrive from a known authenticated source.', 'PREVENTATIVE'),
                                              (2, 1021, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '3b69a362-0354-4843-8444-21340e9d14ce', 'Traffic to known public VPN nodes and/or TOR nodes can be filtered, reducing the ability of attackers to use public privacy tools to evade defences. However, this kind of protection is easily circumvented by domain fronting or custom infrastructure.', 'PREVENTATIVE'),
                                              (2, 1022, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'c60f919a-e240-4574-8f76-fb194a960be2', 'Filtering can be set up to prevent unauthorised devices to send requests associated with operating mode queries. However, this may be complicated to implement in specialised protocol networks, and care must be taken to avoid blocking valid requests.', 'PREVENTATIVE'),
                                              (2, 1023, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '3b69a362-0354-4843-8444-21340e9d14ce', 'Traffic to known public VPN nodes and/or TOR nodes can be filtered, reducing the ability of attackers to use public privacy tools to evade defences. However, this kind of protection is easily circumvented by domain fronting or custom infrastructure.', 'PREVENTATIVE'),
                                              (4, 1024, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Application aware firewalls can filter for payloads associated with program downloads.', 'PREVENTATIVE'),
                                              (4, 1025, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Application aware firewalls can filter for payloads associated with program downloads.', 'DETERRENT'),
                                              (4, 1026, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'Application aware firewalls can filter for payloads associated with program uploads.', 'PREVENTATIVE'),
                                              (4, 1027, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'Application aware firewalls can filter for payloads associated with program uploads.', 'DETERRENT'),
                                              (4, 1028, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Remote services can be configured to be inaccessible outside specific circumstances, reducing the attack surface available to exploit them.', 'PREVENTATIVE'),
                                              (4, 1029, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Attempted access to remote services under suspicious circumstances can be detected by firewall devices.', 'DETECTIVE'),
                                              (3, 1030, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Firewalls on control networks can be configured to intercept control messages coming from unexpected sources. Due care must be taken to ensure that traffic from legitimate sources is not intercepted.', 'PREVENTATIVE'),
                                              (3, 1031, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Firewalls on control networks can be configured to intercept control messages coming from unexpected sources. Due care must be taken to ensure that traffic from legitimate sources is not intercepted.', 'DETECTIVE'),
                                              (3, 1032, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '7e158411-495e-4e93-92e4-65788a9474e9', 'Firewalls on control networks can be configured to intercept reporting messages coming from unexpected sources. Due care must be taken to ensure that traffic from legitimate sources is not intercepted.', 'PREVENTATIVE'),
                                              (3, 1033, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID '7e158411-495e-4e93-92e4-65788a9474e9', 'Firewalls on control networks can be configured to intercept reporting messages coming from unexpected sources.', 'PREVENTATIVE'),
                                              (3, 1034, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'Firewalls on control networks can be configured to intercept control messages coming from unexpected sources. Due care must be taken to ensure that traffic from legitimate sources is not intercepted.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 1035, UUID '62e06071-511e-466d-a516-47af8eb5bff5', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'Firewalls on control networks can be configured to intercept reporting messages coming from unexpected sources. Due care must be taken to ensure that traffic from legitimate sources is not intercepted.', 'DETECTIVE'),
                                              (5, 1036, UUID '13265c34-5864-41b0-87c5-6002aac70260', UUID 'c0931c4b-efbf-4932-a1d1-63a5d23f932a', 'Robust encryption schemes make network sniffing attacks non-viable in practice, limiting disclosure to transport protocol-level information.', 'PREVENTATIVE'),
                                              (5, 1037, UUID '13265c34-5864-41b0-87c5-6002aac70260', UUID '5c19f130-c514-4204-ad4f-1ec2091e4a59', 'Robust encryption schemes make network sniffing attacks non-viable in practice, limiting disclosure to transport protocol-level information.', 'PREVENTATIVE'),
                                              (3, 1038, UUID '13265c34-5864-41b0-87c5-6002aac70260', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'Encryption and cryptographic authentication severely restricts the attacker''s ability to insert themselves into an encrypted traffic stream, especially if peer-to-peer encryption and mutual authentication is used. This does not fully mitigate risks posed by AitM attacks, as the attackers may still intercept traffic.', 'PREVENTATIVE'),
                                              (3, 1039, UUID '13265c34-5864-41b0-87c5-6002aac70260', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Certain encryption schemes may provide authentication and integrity checks, which can help detect tampering attempts.', 'DETECTIVE'),
                                              (4, 1040, UUID '8e5df16f-6a45-4881-bdaf-4ae1c032e714', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'NIDS/NIPS can detect patterns associated with malicious traffic, covering a wide range of MITRE ATT&CK techniques.', 'DETECTIVE'),
                                              (3, 1041, UUID '8e5df16f-6a45-4881-bdaf-4ae1c032e714', UUID '7329201b-174b-488d-a7fc-af8d03b8be43', 'NIDS/NIPS can detect patterns associated with malicious traffic, covering a wide range of MITRE ATTITUDES&CK techniques - including those specific for common protocols and ports. This is based on traffic patterns and IoCs, and the efficacy may vary over time, as attackers evolve their capabilities.', 'DETECTIVE'),
                                              (3, 1042, UUID '8e5df16f-6a45-4881-bdaf-4ae1c032e714', UUID '3b69a362-0354-4843-8444-21340e9d14ce', 'NIDS/NIPS can detect patterns associated with malicious traffic, covering a wide range of MITRE ATTITUDES&CK techniques - including monitoring for suspicious destinations that may serve as connection proxies. This is based on traffic patterns and IoCs, and the efficacy may vary over time, as attackers evolve their capabilities.', 'DETECTIVE'),
                                              (4, 1043, UUID '8e5df16f-6a45-4881-bdaf-4ae1c032e714', UUID '9cbe4c82-270a-431f-8fa6-09db2a3170c5', 'NIDS/NIPS can often detect anomalous transfers over unexpected protocols (FTP, RDP...) with unexpected sources and destinations, thus alerting security operations practitioners to potential lateral movement with a high degree of accuracy unless the threat actor takes evasive action.', 'DETECTIVE'),
                                              (3, 1044, UUID '8e5df16f-6a45-4881-bdaf-4ae1c032e714', UUID 'd4732c86-bcec-4593-bc86-96edc8c8acf8', 'NIDS/NIPS can detect patterns associated with malicious traffic, covering a wide range of MITRE ATTITUDES&CK techniques - including within standard application protocols if deep packet inspection is enabled. This is based on traffic patterns and IoCs, and the efficacy may vary over time, as attackers evolve their capabilities.', 'DETECTIVE'),
                                              (3, 1045, UUID '8e5df16f-6a45-4881-bdaf-4ae1c032e714', UUID 'cd3ac01b-ede9-4745-b684-9d3885622d13', 'NIDS tools can detect traffic associated with user-executed malware based on heuristics and signatures.', 'DETECTIVE'),
                                              (2, 1046, UUID '8e5df16f-6a45-4881-bdaf-4ae1c032e714', UUID '0337b591-892c-4dd3-8f01-fb50983fa325', 'NIDS tools have the capability to detect active scanning activities such as port scanning or IP sweeps, alerting the operators to noisy active reconnaissance events. However, they are unlikely to be able to detect passive discovery activities.', 'DETECTIVE'),
                                              (4, 1047, UUID '5592a9fd-0539-4452-aa62-c237759ad201', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Remote access gateways allow to enforce access policies on external remote services, ensuring enforcement of authentication, authorisation and technical standards such as secure protocols and encryption.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 1048, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (3, 1049, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'f9206252-e522-4d6b-89d2-98de01d91f45', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (3, 1050, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '3c13a4b7-b8c7-45a7-83f3-39c669fec70d', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (4, 1051, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '997e3c17-ff06-4677-9c7d-f8149fe2cc8f', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (4, 1052, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'a24d533c-08e3-46f2-a92d-4dd5696b1927', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (4, 1053, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '593c6d38-c010-4b29-af54-453b6e5bb836', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (5, 1054, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '245d3bec-ea7e-4010-8354-60d6b07fe1f7', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. This is especially effective for removing the threat of an internet accessible device on a segment, as a properly configured gateway will never allow any inbound access.', 'PREVENTATIVE'),
                                              (4, 1055, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '9cbe4c82-270a-431f-8fa6-09db2a3170c5', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (3, 1056, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'ca29a3a1-027c-4ebd-9496-a4a910a2feb8', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (4, 1057, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (4, 1058, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (4, 1059, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE'),
                                              (4, 1060, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment.', 'PREVENTATIVE'),
                                              (4, 1061, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'Data diodes will not allow any traffic in the wrong direction, effectively removing the threat of network-based attacks from outside of their network segment. ', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 1062, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Data diodes will prevent rogue master devices in adjacent networks from accessing the segment guarded by the gateway node, thus limiting the impact on the most critical of network segments.', 'CONTAINMENT'),
                                              (3, 1063, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'a1fb03c7-0f3c-4d88-bea0-49e399e52c69', 'Compromised transient cyber assets cannot be used to access nodes protected by data diodes, thereby limiting the impact.', 'CONTAINMENT'),
                                              (1, 1064, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID 'fddfa472-9838-4855-a4da-39fe354f5241', 'Certain scenarios where a supply chain member is compromised and used for initial access to the industrial installations can be partially mitigated by data diodes, as the compromised supply chain is prevented from entering critical infrastructure from lower security zones.', 'CONTAINMENT'),
                                              (2, 1065, UUID 'b2be82f1-3941-4374-bb3f-a5981e5b9564', UUID '245d3bec-ea7e-4010-8354-60d6b07fe1f7', 'Internet accessible devices from other network segments are restricted from accessing the most critical infrastructure. This does not prevent internet accessible devices from within the segment from accessing outside of it.', 'CONTAINMENT'),
                                              (3, 1066, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '1fe8bc01-dd85-4ada-af9e-a012eac0f872', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (1, 1067, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '32db0b52-a129-41bf-a13a-907ea843c9d6', 'Network segmentation does not meaningfully prevent AitM attacks. It can provide a limited degree of containment of the compromise to a singular network segment.', 'CONTAINMENT'),
                                              (3, 1068, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '068d9598-1033-451f-9597-88a8c59bd522', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (4, 1069, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'dcb3fa1e-23e5-45ef-b6a3-b1961203f07d', 'Isolating devices from the wider network (and the internet at large) is very effective at stopping attempts at exfiltrating data from individual network segments, preventing the largest category of automated collection efforts. Data may still be exfiltrated through in-segment means and/or by bypassing filtering.', 'PREVENTATIVE'),
                                              (3, 1070, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '042139c6-bfa4-4bac-af20-ecdc30cb9385', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1071, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'f9206252-e522-4d6b-89d2-98de01d91f45', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1072, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '3b69a362-0354-4843-8444-21340e9d14ce', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'DETERRENT'),
                                              (3, 1073, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'c60f919a-e240-4574-8f76-fb194a960be2', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1074, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '3c13a4b7-b8c7-45a7-83f3-39c669fec70d', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 1075, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'b2dbcaa6-316a-4b34-92e4-47a78e9c7bb6', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1076, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'c0931c4b-efbf-4932-a1d1-63a5d23f932a', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1077, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '14fb1d12-0a85-403f-af59-3dc4b9001dca', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1078, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1079, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '0c93964d-67b2-4a2c-8b49-c2d5220fc33f', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1080, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '7ce5b083-1b39-462b-85d9-cdacd6e2fb5c', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1081, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '0337b591-892c-4dd3-8f01-fb50983fa325', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1082, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '8956c3cb-7899-4cd3-b4aa-01330f893883', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1083, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1084, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1085, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID '5c19f130-c514-4204-ad4f-1ec2091e4a59', 'Depending on the maturity level of the network segmentation, it can significantly restrict the ability of attackers to access the environment laterally from compromised devices to only the associated network segment.', 'PREVENTATIVE'),
                                              (3, 1086, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'a1fb03c7-0f3c-4d88-bea0-49e399e52c69', 'Transient assets can be segregated into dedicated demilitarised zones, further limiting their access and ensuring unidirectional access only.', 'PREVENTATIVE'),
                                              (4, 1087, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'c0931c4b-efbf-4932-a1d1-63a5d23f932a', 'Proper segmentation reduces the blast radius of network sniffing attacks to the immediate network segment.', 'CONTAINMENT');
INSERT INTO "PUBLIC"."TECHNIQUE_COVERAGE" VALUES
                                              (3, 1088, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'f8fc81d1-7ccc-4447-b4b7-98bf46deb293', 'Rogue masters'' impact is restricted to their immediate network segment only.', 'CONTAINMENT'),
                                              (3, 1089, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'e932aef6-0438-43ad-a4e5-5f5d49b3215f', 'The impact of unauthorized command messages will be contained to the immediate network segment only.', 'CONTAINMENT'),
                                              (3, 1090, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'a1fb03c7-0f3c-4d88-bea0-49e399e52c69', 'Transient cyber assets will only have access to their dedicated network segments, limiting the blast radius of one''s compromise.', 'CONTAINMENT'),
                                              (1, 1091, UUID 'de342946-9ab4-42db-b91b-579722022c6e', UUID 'fddfa472-9838-4855-a4da-39fe354f5241', 'Network segmentation provides a small degree of containment for supply chain compromise in cases when a third party support provider is compromised, or when the compromised vendor isn''t widely leveraged across the full network. Such compromises'' blast radius is then limited to immediate network segment only.', 'CONTAINMENT'),
                                              (4, 4652, UUID 'e00ea934-3608-4318-9521-cf4d09f10c8c', UUID '01509832-f76c-4fdf-8aee-688667a163b3', 'Code signing cryptographically verifies firmware authenticity and integrity, preventing malicious firmware uploads in 75-90% of standard attack scenarios. However, edge cases including downgrade attacks, physical JTAG attacks, compromised signing keys, and weak verification implementations limit effectiveness. Legacy systems without enforcement create additional gaps.', 'PREVENTATIVE'),
                                              (4, 4653, UUID 'e00ea934-3608-4318-9521-cf4d09f10c8c', UUID '10c96bfc-c884-413d-bb61-cbdc1abfc556', 'Code signing effectively prevents malicious firmware installation on modular components by requiring cryptographic validation before execution. However, legacy modular devices (particularly Ethernet cards) may lack code signing support, and vulnerabilities in signature verification implementations can be exploited to bypass the control.', 'PREVENTATIVE'),
                                              (4, 4654, UUID 'e00ea934-3608-4318-9521-cf4d09f10c8c', UUID '5b8d94ac-b1ae-409d-baa4-c0582bc2398e', 'Code signing prevents execution of infected project files by validating signatures at both engineering workstation and PLC device levels. The control detects tampering and enforces source verification through external OEM and internal site-specific signatures. Limitations include incomplete enforcement across engineering tools and risk of compromised signing keys.', 'PREVENTATIVE'),
                                              (4, 4655, UUID 'e00ea934-3608-4318-9521-cf4d09f10c8c', UUID 'fddfa472-9838-4855-a4da-39fe354f5241', 'Code signing prevents execution of tampered code introduced during supply chain delivery by verifying cryptographic authenticity. However, the control cannot protect against compromise of OEM signing infrastructure itself, compromised development tools before signing, or non-code supply chain attack vectors such as physical tampering or manipulated update servers.', 'PREVENTATIVE'),
                                              (2, 4656, UUID 'e00ea934-3608-4318-9521-cf4d09f10c8c', UUID 'fcb8bf14-cff5-4a47-a13b-aa1c4c04c6b0', 'Code signing provides minimal detective value against exploitation for evasion because it validates code integrity pre-execution but cannot detect exploitation of vulnerabilities within legitimately signed firmware. An attacker exploiting signed firmware to disable security features like RAM/ROM checks will evade detection entirely, as the base firmware remains cryptographically valid.', 'DETECTIVE'),
                                              (4, 4657, UUID 'e00ea934-3608-4318-9521-cf4d09f10c8c', UUID '7edb70b6-837a-499d-927d-bebb113797db', 'Code signing enforces cryptographic verification of program authenticity before execution, preventing unauthorized modifications through Program Download, online edit, or program append operations. The control effectively prevents 75-90% of modification vectors but is limited by potential key compromise, legacy systems lacking enforcement, and implementation weaknesses.', 'PREVENTATIVE'),
                                              (4, 4658, UUID 'e00ea934-3608-4318-9521-cf4d09f10c8c', UUID '766222eb-ebd7-4c8f-9939-8e2dbd85afaf', 'Code signing prevents unauthorized program downloads by validating cryptographic signatures before code execution, ensuring programs originate from trusted sources. The control establishes a chain of trust across vendor and site-specific configurations but is limited by legacy device support, potential for compromised signing keys, and weak enforcement implementations.', 'PREVENTATIVE');
INSERT INTO "PUBLIC"."TACTIC" VALUES
                                  (UUID 'ff63cc2f-bdc3-4393-8e0b-cbe8d2622799', U&'The adversary is trying to gather data of interest and domain knowledge on your ICS environment to inform their goal.\000a\000aCollection consists of techniques adversaries use to gather domain knowledge and obtain contextual feedback in an ICS environment. This tactic is often performed as part of [Discovery](https://attack.mitre.org/tactics/TA0102), to compile data on control systems and targets of interest that may be used to follow through on the adversary\2019s objective. Examples of these techniques include observing operation states, capturing screenshots, identifying unique device roles, and gathering system and diagram schematics. Collection of this data can play a key role in planning, executing, and even revising an ICS-targeted attack. Methods of collection depend on the categories of data being targeted, which can include protocol specific, device specific, and process specific configurations and functionality. Information collected may pertain to a combination of system, supervisory, device, and network related data, which conceptually fall under high, medium, and low levels of plan operations. For example, information repositories on plant data at a high level or device specific programs at a low level. Sensitive floor plans, vendor device manuals, and other references may also be at risk and exposed on the internet or otherwise publicly accessible.', 'TA0100', 'https://attack.mitre.org/tactics/TA0100', 'Collection'),
                                  (UUID '1463a16b-bf70-47b9-8a3d-12d6e7f1c2d6', U&'The adversary is trying to communicate with and control compromised systems, controllers, and platforms with access to your ICS environment.\000a\000aCommand and Control consists of techniques that adversaries use to communicate with and send commands to compromised systems, devices, controllers, and platforms with specialized applications used in ICS environments. Examples of these specialized communication devices include human machine interfaces (HMIs), data historians, SCADA servers, and engineering workstations (EWS). Adversaries often seek to use commonly available resources and mimic expected network traffic to avoid detection and suspicion. For instance, commonly used ports and protocols in ICS environments, and even expected IT resources, depending on the target network. Command and Control may be established to varying degrees of stealth, often depending on the victim\2019s network structure and defenses.', 'TA0101', 'https://attack.mitre.org/tactics/TA0101', 'Command and Control'),
                                  (UUID 'c348d074-f203-4164-870c-abc13e2a36bd', U&'The adversary is locating information to assess and identify their targets in your environment.\000a\000aDiscovery consists of techniques that adversaries use to survey your ICS environment and gain knowledge about the internal network, control system devices, and how their processes interact. These techniques help adversaries observe the environment and determine next steps for target selection and Lateral Movement. They also allow adversaries to explore what they can control and gain insight on interactions between various control system processes. Discovery techniques are often an act of progression into the environment which enable the adversary to orient themselves before deciding how to act. Adversaries may use Discovery techniques that result in Collection, to help determine how available resources benefit their current objective. A combination of native device communications and functions, and custom tools are often used toward this post-compromise information-gathering objective.', 'TA0102', 'https://attack.mitre.org/tactics/TA0102', 'Discovery'),
                                  (UUID '63ac30ce-d1dd-433d-a19b-497a2fbbf67b', U&'The adversary is trying to avoid security defenses.\000a\000aEvasion consists of techniques that adversaries use to avoid technical defenses throughout their campaign. Techniques used for evasion include removal of indicators of compromise, spoofing communications, and exploiting software vulnerabilities. Adversaries may also leverage and abuse trusted devices and processes to hide their activity, possibly by masquerading as master devices or native software. Methods of defense evasion for this purpose are often more passive in nature.', 'TA0103', 'https://attack.mitre.org/tactics/TA0103', 'Evasion');
INSERT INTO "PUBLIC"."TACTIC" VALUES
                                  (UUID 'c1c1816b-2ef5-4bd1-9c7b-59c95885163a', U&'The adversary is trying to run code or manipulate system functions, parameters, and data in an unauthorized way.\000a\000aExecution consists of techniques that result in adversary-controlled code running on a local or remote system, device, or other asset. This execution may also rely on unknowing end users or the manipulation of device operating modes to run. Adversaries may infect remote targets with programmed executables or malicious project files that operate according to specified behavior and may alter expected device behavior in subtle ways. Commands for execution may also be issued from command-line interfaces, APIs, GUIs, or other available interfaces. Techniques that run malicious code may also be paired with techniques from other tactics, particularly to aid network [Discovery](https://attack.mitre.org/tactics/TA0102) and [Collection](https://attack.mitre.org/tactics/TA0100), impact operations, and inhibit response functions.', 'TA0104', 'https://attack.mitre.org/tactics/TA0104', 'Execution'),
                                  (UUID '98c79849-cf8d-4adb-9ea5-247bc4591ce0', U&'The adversary is trying to manipulate, interrupt, or destroy your ICS systems, data, and their surrounding environment.\000a\000aImpact consists of techniques that adversaries use to disrupt, compromise, destroy, and manipulate the integrity and availability of control system operations, processes, devices, and data. These techniques encompass the influence and effects resulting from adversarial efforts to attack the ICS environment or that tangentially impact it. Impact techniques can result in more instantaneous disruption to control processes and the operator, or may result in more long term damage or loss to the ICS environment and related operations. The adversary may leverage [Impair Process Control](https://attack.mitre.org/tactics/TA0106) techniques, which often manifest in more self-revealing impacts on operations, or [Impair Process Control](https://attack.mitre.org/tactics/TA0106) techniques to hinder safeguards and alarms in order to follow through with and provide cover for Impact. In some scenarios, control system processes can appear to function as expected, but may have been altered to benefit the adversary\2019s goal over the course of a longer duration. These techniques might be used by adversaries to follow through on their end goal or to provide cover for a confidentiality breach.\000a\000a[Loss of Productivity and Revenue](https://attack.mitre.org/techniques/T0828), [Theft of Operational Information](https://attack.mitre.org/techniques/T0882), and [Damage to Property](https://attack.mitre.org/techniques/T0879) are meant to encompass some of the more granular goals of adversaries in targeted and untargeted attacks. These techniques in and of themselves are not necessarily detectable, but the associated adversary behavior can potentially be mitigated and/or detected.', 'TA0105', 'https://attack.mitre.org/tactics/TA0105', 'Impact'),
                                  (UUID 'cca118b9-ed4c-4506-ade1-9ef06f1b45db', U&'The adversary is trying to manipulate, disable, or damage physical control processes.\000a\000aImpair Process Control consists of techniques that adversaries use to disrupt control logic and cause determinantal effects to processes being controlled in the target environment. Targets of interest may include active procedures or parameters that manipulate the physical environment. These techniques can also include prevention or manipulation of reporting elements and control logic. If an adversary has modified process functionality, then they may also obfuscate the results, which are often self-revealing in their impact on the outcome of a product or the environment. The direct physical control these techniques exert may also threaten the safety of operators and downstream users, which can prompt response mechanisms. Adversaries may follow up with or use [Inhibit Response Function](https://attack.mitre.org/tactics/TA0107) techniques in tandem, to assist with the successful abuse of control processes to result in [Impact](https://attack.mitre.org/tactics/TA0105).', 'TA0106', 'https://attack.mitre.org/tactics/TA0106', 'Impair Process Control');
INSERT INTO "PUBLIC"."TACTIC" VALUES
                                  (UUID 'e3e96ede-d8a1-4fd7-8a68-9bb53bdde34b', U&'The adversary is trying to prevent your safety, protection, quality assurance, and operator intervention functions from responding to a failure, hazard, or unsafe state.\000a\000aInhibit Response Function consists of techniques that adversaries use to hinder the safeguards put in place for processes and products. This may involve the inhibition of safety, protection, quality assurance, or operator intervention functions to disrupt safeguards that aim to prevent the loss of life, destruction of equipment, and disruption of production. These techniques aim to actively deter and prevent expected alarms and responses that arise due to statuses in the ICS environment. Adversaries may modify or update system logic, or even outright prevent responses with a denial-of-service. They may result in the prevention, destruction, manipulation, or modification of programs, logic, devices, and communications. As prevention functions are generally dormant, reporting and processing functions can appear fine, but may have been altered to prevent failure responses in dangerous scenarios. Unlike [Evasion](https://attack.mitre.org/tactics/TA0103), Inhibit Response Function techniques may be more intrusive, such as actively preventing responses to a known dangerous scenario. Adversaries may use these techniques to follow through with or provide cover for [Impact](https://attack.mitre.org/tactics/TA0105) techniques.', 'TA0107', 'https://attack.mitre.org/tactics/TA0107', 'Inhibit Response Function'),
                                  (UUID '0eb98e95-cff5-4671-b129-034da91f3db1', U&'The adversary is trying to get into your ICS environment.\000a\000aInitial Access consists of techniques that adversaries may use as entry vectors to gain an initial foothold within an ICS environment. These techniques include compromising operational technology assets, IT resources in the OT network, and external remote services and websites. They may also target third party entities and users with privileged access. In particular, these initial access footholds may include devices and communication mechanisms with access to and privileges in both the IT and OT environments. IT resources in the OT environment are also potentially vulnerable to the same attacks as enterprise IT systems. Trusted third parties of concern may include vendors, maintenance personnel, engineers, external integrators, and other outside entities involved in expected ICS operations. Vendor maintained assets may include physical devices, software, and operational equipment. Initial access techniques may also leverage outside devices, such as radios, controllers, or removable media, to remotely interfere with and possibly infect OT operations.', 'TA0108', 'https://attack.mitre.org/tactics/TA0108', 'Initial Access'),
                                  (UUID '0600f4c9-f3a6-4935-a7e0-b23be9d691aa', U&'The adversary is trying to move through your ICS environment.\000a\000aLateral Movement consists of techniques that adversaries use to enter and control remote systems on a network. These techniques abuse default credentials, known accounts, and vulnerable services, and may also leverage dual-homed devices and systems that reside on both the IT and OT networks. The adversary uses these techniques to pivot to their next point in the environment, positioning themselves to where they want to be or think they should be. Following through on their primary objective often requires [Discovery](https://attack.mitre.org/tactics/TA0102) of the network and [Collection](https://attack.mitre.org/tactics/TA0100) to develop awareness of unique ICS devices and processes, in order to find their target and subsequently gain access to it. Reaching this objective often involves pivoting through multiple systems, devices, and accounts. Adversaries may install their own remote tools to accomplish Lateral Movement or leverage default tools, programs, and manufacturer set or other legitimate credentials native to the network, which may be stealthier.', 'TA0109', 'https://attack.mitre.org/tactics/TA0109', 'Lateral Movement');
INSERT INTO "PUBLIC"."TACTIC" VALUES
                                  (UUID '80e089da-52b6-4163-b6e4-6a46371b9c91', U&'The adversary is trying to maintain their foothold in your ICS environment.\000a\000aPersistence consists of techniques that adversaries use to maintain access to ICS systems and devices across restarts, changed credentials, and other interruptions that could cut off their access. Techniques used for persistence include any access, action, or configuration changes that allow them to secure their ongoing activity and keep their foothold on systems. This may include replacing or hijacking legitimate code, firmware, and other project files, or adding startup code and downloading programs onto devices.', 'TA0110', 'https://attack.mitre.org/tactics/TA0110', 'Persistence'),
                                  (UUID '6234eea2-048a-49d9-9751-a44878fbed90', U&'The adversary is trying to gain higher-level permissions.\000a\000aPrivilege Escalation consists of techniques that adversaries use to gain higher-level permissions on a system or network. Adversaries can often enter and explore a network with unprivileged access but require elevated permissions to follow through on their objectives. Common approaches are to take advantage of system weaknesses, misconfigurations, and vulnerabilities.', 'TA0111', 'https://attack.mitre.org/tactics/TA0111', 'Privilege Escalation');
